Index: bench-targets/cli-flags/src/parseArgs.mjs
===================================================================
--- bench-targets/cli-flags/src/parseArgs.mjs	
+++ bench-targets/cli-flags/src/parseArgs.mjs	
@@ -1,9 +1,27 @@
 export function parseArgs(argv) {
   const result = { _: [] }
-  for (let index = 0; index < argv.length; index += 1) {
-    const arg = argv[index]
-    if (!arg.startsWith('--')) result._.push(arg)
-    else result[arg.slice(2)] = true
+  let i = 0
+  while (i < argv.length) {
+    const arg = argv[i]
+    if (!arg.startsWith('--')) {
+      result._.push(arg)
+      i += 1
+      continue
+    }
+    if (arg.includes('=')) {
+      const [key, value] = arg.split('=', 2)
+      result[key.slice(2)] = value
+      i += 1
+      continue
+    }
+    const key = arg.slice(2)
+    if (i + 1 < argv.length && !argv[i + 1].startsWith('--') && !argv[i + 1].includes('=')) {
+      result[key] = argv[i + 1]
+      i += 2
+      continue
+    }
+    result[key] = true
+    i += 1
   }
   return result
 }

